# ── Seeding Logic ─────────────────────────────────────────────────────────────

async def seed_questions():
    import aiosqlite
    from config import DB_PATH

    async with aiosqlite.connect(DB_PATH) as db:
        db.row_factory = aiosqlite.Row
        await db.execute("PRAGMA journal_mode=WAL")

        async with db.execute("SELECT COUNT(*) as cnt FROM survey_questions") as cur:
            row = await cur.fetchone()
            if row["cnt"] > 0:
                return  # already seeded

        rows = [
            (q[1], q[2], q[3], q[0], json.dumps(q[4]), json.dumps(q[5]))
            for q in QUESTIONS
        ]
        await db.executemany(
            "INSERT INTO survey_questions(template_en, template_es, category, type, options_en, options_es) VALUES(?,?,?,?,?,?)",
            rows,
        )

        # Seed default admin PIN
        await db.execute(
            "INSERT OR IGNORE INTO app_config(key, value) VALUES('admin_pin', '1234')"
        )
        await db.execute(
            "INSERT OR IGNORE INTO app_config(key, value) VALUES('admin_pin_is_default', 'true')"
        )
        await db.commit()
        print(f"Seeded {len(rows)} questions into survey_questions.")
